#include <bits/stdc++.h>
using namespace std;

int n;

string solve(int x) {
    if (x == 1) return "2(0)";
    if (x == 2) return "2";
    if ((x & (x - 1)) == 0) {
        return "2(" + solve(log2(x)) + ")";
    }
    string ans;
    int i = 1;
    while (x) {
        if (x & 1) {
            ans = solve(i) + "+" + ans;
            // ans = "solve(" + solve(i) + ") + " + ans;
            // ans = "solve(" + string(1, char(i + '0')) + ")" + "+" + ans;
            // printf(">>> %d = %s\n", x, ans.c_str());
        }
        x >>= 1;
        i <<= 1;
    }
    ans.erase(ans.size() - 1);
    return ans;
}

int main() {
    cin >> n;
    cout << solve(n);
    return 0;
}
